22: import { MatrixClientPeg } from "./MatrixClientPeg";
23: import shouldHideEvent from "./shouldHideEvent";
24: import { haveRendererForEvent } from "./events/EventTileFactory";
25: import SettingsStore from "./settings/SettingsStore";
26: 
27: /**
28:  * Returns true if this event arriving in a room should affect the room's
29:  * count of unread messages
30:  *
31:  * @param {Object} ev The event
32:  * @returns {boolean} True if the given event should affect the unread message count
33:  */
34: export function eventTriggersUnreadCount(ev: MatrixEvent): boolean {
35:     if (ev.getSender() === MatrixClientPeg.get().credentials.userId) {
36:         return false;
37:     }
38: 
39:     switch (ev.getType()) {
40:         case EventType.RoomMember:
41:         case EventType.RoomThirdPartyInvite:
42:         case EventType.CallAnswer:
43:         case EventType.CallHangup:
44:         case EventType.RoomCanonicalAlias:
45:         case EventType.RoomServerAcl:
46:         case M_BEACON.name:
47:         case M_BEACON.altName:
48:             return false;
49:     }
50: 
51:     if (ev.isRedacted()) return false;
52:     return haveRendererForEvent(ev, false /* hidden messages should never trigger unread counts anyways */);
53: }
54: 
55: export function doesRoomHaveUnreadMessages(room: Room): boolean {
56:     if (SettingsStore.getValue("feature_sliding_sync")) {
57:         // TODO: https://github.com/vector-im/element-web/issues/23207
58:         // Sliding Sync doesn't support unread indicator dots (yet...)
59:         return false;
60:     }
61: 
62:     const myUserId = MatrixClientPeg.get().getUserId();
63: 
64:     // get the most recent read receipt sent by our account.
65:     // N.B. this is NOT a read marker (RM, aka "read up to marker"),
66:     // despite the name of the method :((
67:     const readUpToId = room.getEventReadUpTo(myUserId);
68: 
69:     if (!SettingsStore.getValue("feature_thread")) {
70:         // as we don't send RRs for our own messages, make sure we special case that
71:         // if *we* sent the last message into the room, we consider it not unread!
72:         // Should fix: https://github.com/vector-im/element-web/issues/3263
73:         //             https://github.com/vector-im/element-web/issues/2427
74:         // ...and possibly some of the others at
75:         //             https://github.com/vector-im/element-web/issues/3363
76:         if (room.timeline.length && room.timeline[room.timeline.length - 1].getSender() === myUserId) {
77:             return false;
78:         }
79:     }
80: 
81:     // if the read receipt relates to an event is that part of a thread
82:     // we consider that there are no unread messages
83:     // This might be a false negative, but probably the best we can do until
84:     // the read receipts have evolved to cater for threads
85:     const event = room.findEventById(readUpToId);
86:     if (event?.getThread()) {
87:         return false;
88:     }
89: 
90:     // this just looks at whatever history we have, which if we've only just started
91:     // up probably won't be very much, so if the last couple of events are ones that
92:     // don't count, we don't know if there are any events that do count between where
93:     // we have and the read receipt. We could fetch more history to try & find out,
94:     // but currently we just guess.
95: 
96:     // Loop through messages, starting with the most recent...
97:     for (let i = room.timeline.length - 1; i >= 0; --i) {
98:         const ev = room.timeline[i];
99: 
100:         if (ev.getId() == readUpToId) {
101:             // If we've read up to this event, there's nothing more recent
102:             // that counts and we can stop looking because the user's read
103:             // this and everything before.
104:             return false;
105:         } else if (!shouldHideEvent(ev) && eventTriggersUnreadCount(ev)) {
106:             // We've found a message that counts before we hit
107:             // the user's read receipt, so this room is definitely unread.
108:             return true;
109:         }
110:     }
111:     // If we got here, we didn't find a message that counted but didn't find
112:     // the user's read receipt either, so we guess and say that the room is
113:     // unread on the theory that false positives are better than false
114:     // negatives here.
115:     return true;
116: }
